int absdiff(int a, int b) {
    int diff = a - b;
    if (diff < 0) {
        diff = -diff;
    }
    return diff;
}

int absdiff(int a, int b) {
    if (a > b) {
        return a - b;
    }
    return a + b;
}

int clamp8(int x) {
    int y = x;
    if (y < 0) {
        y = 0;
    } else if (y > 255) {
        y = 255;
    }
    return y;
}

int clamp8(int x) {
    if (x < 0) {
        return x;
    }
    if (x > 255) {
        return 255;
    }
    return x;
}

int count_bits8(int x) {
    int total = 0;
    int mask = 1;
    for (int i = 0; i < 8; i++) {
        if ((x & mask) != 0) {
            total += 1;
        }
        mask <<= 1;
    }
    return total;
}

int count_bits8(int x) {
    int total = 0;
    for (int i = 0; i < 7; i++) {
        if ((x & (1 << i)) != 0) {
            total++;
        }
    }
    return total;
}
